#include <iostream>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>
#include <unistd.h>

#define PORT 8000
#define BUFFER_SIZE 1024

struct Packet {
    char type;
    float x, y, z;
};

bool receiveFromClient(int clientSocket) {
    Packet packet;
    int bytesReceived = recv(clientSocket, (char*)&packet, BUFFER_SIZE, 0);
    
    if (bytesReceived < 1) {
        std::cout << "Client disconnected" << std::endl;
        return false;
    }

    switch(packet.type) {
        case 'p': // Position update
            std::cout << "Player position updated to: (" << packet.x << ", " << packet.y << ", " << packet.z << ")" << std::endl;
            break;
        case 's': // Shooting action
            if (packet.x == 0.5 && packet.y == 0.7) {
                std::cout << "Player shot target at (" << packet.x << ", " << packet.y << ", " << packet.z << ")" << std::endl;
            }
            break;
    }

    return true;
}

int main() {
    // Create UDP socket
    int serverSocket = socket(AF_INET, SOCK_DGRAM, 0);

    if (serverSocket < 0) {
        std::cerr << "Could not create server socket" << std::endl;
        return -1;
    }

    // Set up address and port for listening
    struct sockaddr_in serverAddress;
    serverAddress.sin_family = AF_INET;
    serverAddress.sin_port = htons(PORT);
    inet_pton(AF_INET, "127.0.0.1", &serverAddress.sin_addr);

    // Bind to the socket
    if (bind(serverSocket, (struct sockaddr*)&serverAddress, sizeof(serverAddress)) < 0) {
        std::cerr << "Could not bind server socket" << std::endl;
        return -2;
    }

    while(true) {
        Packet packet;
        struct sockaddr_in clientAddress;
        socklen_t clientLength = sizeof(clientAddress);

        int bytesReceived = recvfrom(serverSocket, (char*)&packet, BUFFER_SIZE, 0, (struct sockaddr*)&clientAddress, &clientLength);
        
        if (bytesReceived < 1) {
            std::cout << "Client disconnected" << std::endl;
            continue;
        }

        receiveFromClient(serverSocket);
    }

    close(serverSocket);

    return 0;
}